mapper.select:
SELECT cd.species_id AS speciesId, cd.species_name AS speciesName, SUM(cd.catch_count) AS totalCount, SUM(cd.total_weight) AS totalWeight FROM catch_detail cd INNER JOIN fishing_record fr ON cd.record_id = fr.record_id AND fr.deleted = 0
fr.user_id = #{userId}
AND DATE_FORMAT(fr.fishing_date, '%Y-%m') = #{month}
AND EXISTS ( SELECT 1 FROM fishing_spot fs WHERE fs.spot_id = fr.spot_id AND fs.deleted = 0
AND fs.water_type = #{waterType}
)
AND fr.fishing_method = #{fishingMethod}
GROUP BY cd.species_id, cd.species_name ORDER BY totalCount DESC, totalWeight DESC
